%[text] # 例10.1（深層展開：LISTA）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2026a
%[text] ## 準備
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example10_01"; %#ok<NASGU>

imgname = "msipimg05";
imgfmt  = "tiff";

rng(0)
close all
%%
%[text] ## 画像データの読込
szOrg = [96 96];
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),szOrg,'bilinear');
%%
%[text] ## ノイズ付加
sigmaW = 25/255;
V = X + sigmaW * randn(size(X));
psnr_noisy = psnr(V,X);
fprintf("観測画像 PSNR: %.2f dB\n", psnr_noisy) %[output:130b17c8]
%%
%[text] ## パラメータ設定
%[text] ### 辞書の設定
%[text] 例9.2の K-SVD 学習済み辞書を再利用（ない場合は DCT を使用）
szBlk = [8 8];
M = prod(szBlk);  % 64

dictFile = fullfile(datfolder,"example09_02_learnedDicts.mat");
if isfile(dictFile) %[output:group:0583fac8]
    D09 = load(dictFile);
    D_syn = double(D09.Phi_ksvd);  % M×L synthesis dictionary
    fprintf("K-SVD辞書を読み込みました (size: %d×%d)\n", size(D_syn,1), size(D_syn,2)) %[output:4d6263f0]
else
    C8 = dctmtx(8);
    D_syn = kron(C8,C8)';   % M×M orthogonal DCT synthesis dict (columns = atoms)
    fprintf("DCT辞書を使用します\n")
end %[output:group:0583fac8]
[~, L] = size(D_syn);   % M×L
D_ana = D_syn';          % L×M analysis dictionary (= D_θ^T)

%[text] ### ISTAパラメータ
%[text] ステップサイズ $\\tau = 1/|\\mathbf{D}|^2$ (リプシッツ定数の逆数)
step_size = 0.99 / norm(D_syn)^2;
lambda    = sigmaW * 0.5;
tau_ista  = lambda * step_size;
T = 5;    % ステージ数

Q_ista = eye(L) - step_size * (D_ana * D_syn);   % L×L
Y_ista = step_size * (D_ana * im2col(V, szBlk, 'distinct'));  % L×nPatches
nPatches = size(Y_ista, 2);
Xp = im2col(X, szBlk, 'distinct');  % M×nPatches
fprintf("ステップサイズ: %.4f  しきい値: %.6f  パッチ数: %d\n", step_size, tau_ista, nPatches) %[output:42fe190a]
%%
%[text] ## ISTAによるデノイジング（比較用）
%[text] $\\mathbf{s}^{(t+1)}\\leftarrow\\phi\_\\mathrm{ST}(\\mathbf{y}+\\mathbf{Q}\\mathbf{s}^{(t)};\\tau)$
S_ista = zeros(L, nPatches);
psnr_ista_t = zeros(T,1);
for t = 1:T
    U = Y_ista + Q_ista * S_ista;
    S_ista = max(U - tau_ista, 0) - max(-U - tau_ista, 0);
    Xt = col2im(D_syn * S_ista, szBlk, szOrg, 'distinct');
    psnr_ista_t(t) = psnr(Xt, X);
end
X_ista = col2im(D_syn * S_ista, szBlk, szOrg, 'distinct');
fprintf("ISTA (T=%d) PSNR: %.2f dB\n", T, psnr_ista_t(T)) %[output:56d69a26]
%%
%[text] ## LISTAの学習
%[text] 学習可能なパラメータ:
%[text] - $\\mathbf{W}\_e$: 符号化行列（初期値 $\\mu\\mathbf{D}^\\top$）
%[text] - $\\mathbf{Q}$: フィードバック行列（初期値 $\\mathbf{I}-\\mu\\mathbf{D}^\\top\\mathbf{D}$）
%[text] - $\\tau$: ソフト閾値パラメータ（log空間で学習） \
We     = dlarray(single(step_size * D_ana));  % L×M
Q_dl   = dlarray(single(Q_ista));             % L×L
logtau = dlarray(single(log(tau_ista)));      % スカラー

Vp_s = single(im2col(V, szBlk, 'distinct'));  % M×nPatches
Xp_s = single(Xp);
D_syn_s = single(D_syn);

% Adamオプティマイザの状態
lr = 1e-3; beta1 = 0.9; beta2 = 0.999; eps_a = 1e-8;
avgG_We = zeros(size(We),'single');    avgSqG_We = zeros(size(We),'single');
avgG_Q  = zeros(size(Q_dl),'single'); avgSqG_Q  = zeros(size(Q_dl),'single');
avgG_lt = single(0);                   avgSqG_lt = single(0);

batchSize = min(64, nPatches);
nEpochs   = 500;
lossHist  = zeros(nEpochs, 1);

for epoch = 1:nEpochs
    idx = randperm(nPatches, batchSize);
    Vb = dlarray(Vp_s(:,idx));
    Xb = dlarray(Xp_s(:,idx));
    [loss, gWe, gQ, glt] = dlfeval(@listaLoss, We, Q_dl, logtau, D_syn_s, Vb, Xb, T);
    [We,    avgG_We, avgSqG_We] = adamupdate(We,    gWe, avgG_We, avgSqG_We, epoch, lr, beta1, beta2, eps_a);
    [Q_dl,  avgG_Q,  avgSqG_Q]  = adamupdate(Q_dl,  gQ,  avgG_Q,  avgSqG_Q,  epoch, lr, beta1, beta2, eps_a);
    [logtau,avgG_lt, avgSqG_lt] = adamupdate(logtau,glt, avgG_lt, avgSqG_lt, epoch, lr, beta1, beta2, eps_a);
    lossHist(epoch) = extractdata(loss);
end
%%
%[text] ## LISTAの評価
We_f  = double(extractdata(We));
Q_f   = double(extractdata(Q_dl));
tau_f = exp(double(extractdata(logtau)));
fprintf("学習後のしきい値 τ = %.6f\n", tau_f) %[output:8fae5721]

Vp = im2col(V, szBlk, 'distinct');
Y_lista = We_f * Vp;
S_lista = zeros(L, nPatches);
psnr_lista_t = zeros(T,1);
for t = 1:T
    U = Y_lista + Q_f * S_lista;
    S_lista = max(U - tau_f, 0) - max(-U - tau_f, 0);
    Xt = col2im(D_syn * S_lista, szBlk, szOrg, 'distinct');
    psnr_lista_t(t) = psnr(Xt, X);
end
X_lista = col2im(D_syn * S_lista, szBlk, szOrg, 'distinct');
fprintf("LISTA (T=%d) PSNR: %.2f dB\n", T, psnr_lista_t(T)) %[output:554e4a00]
%%
%[text] ## 結果の表示
fontSize = 14;

figure(1)
subplot(1,4,1); imshow(X);       title('原画像','FontSize',12) %[output:94f2d1c5]
subplot(1,4,2); imshow(V);       title(sprintf('観測 (%.2f dB)',psnr_noisy),'FontSize',12) %[output:94f2d1c5]
subplot(1,4,3); imshow(X_ista);  title(sprintf('ISTA T=%d (%.2f dB)',T,psnr_ista_t(T)),'FontSize',12) %[output:94f2d1c5]
subplot(1,4,4); imshow(X_lista); title(sprintf('LISTA T=%d (%.2f dB)',T,psnr_lista_t(T)),'FontSize',12) %[output:94f2d1c5]

figure(2)
subplot(1,2,1) %[output:7288b653]
plot(lossHist,'k-','LineWidth',1.5) %[output:7288b653]
xlabel('エポック数','FontSize',fontSize) %[output:7288b653]
ylabel('損失','FontSize',fontSize) %[output:7288b653]
title('LISTA 学習曲線') %[output:7288b653]
grid on %[output:7288b653]

subplot(1,2,2) %[output:45d865ea]
plot(1:T, psnr_ista_t, 'k--o', 'LineWidth',2, 'MarkerSize',8, 'DisplayName','ISTA') %[output:45d865ea]
hold on %[output:45d865ea]
plot(1:T, psnr_lista_t,'k-s',  'LineWidth',2, 'MarkerSize',8, 'DisplayName','LISTA') %[output:45d865ea]
hold off %[output:45d865ea]
xlabel('ステージ数 T','FontSize',fontSize) %[output:45d865ea]
ylabel('PSNR [dB]','FontSize',fontSize) %[output:45d865ea]
legend('Location','southeast','FontSize',fontSize-2) %[output:45d865ea]
title('ステージ数と PSNR の比較') %[output:45d865ea]
set(gca,'FontSize',fontSize) %[output:45d865ea]
grid on %[output:45d865ea]
set(gcf,'PaperUnits','inches','PaperSize',[8.26 5.16],'PaperPosition',[0 0 8.26 5.16])
print(gcf, fullfile(resfolder,'fig10-01.png'),'-dpng','-r96') %[output:45d865ea]

%%
%[text] ## 【関数定義】

function [loss, gWe, gQ, glt] = listaLoss(We, Q, logtau, D_syn, V, X_star, T)
%LISTALOSS  LISTAの損失関数と勾配を計算する
tau = exp(logtau);
Y   = We * V;                          % エンコード
S   = zeros(size(Y), 'like', Y);      % スパース係数の初期化
for t = 1:T
    U = Y + Q * S;
    S = max(U - tau, 0) - max(-U - tau, 0);   % ソフト閾値処理
end
X_hat = dlarray(D_syn) * S;           % デコード（Dは固定）
loss  = mean((X_star - X_hat).^2, 'all');
[gWe, gQ, glt] = dlgradient(loss, We, Q, logtau);
end

